  { "id": 1044, "en": "risky", "ar": "محفوف بالمخاطر", "pronounce": "رِسْكِي", "ex_en": "Investing here is risky.", "ar_ex": "الاستثمارُ هنا محفوفٌ بالمخاطرِ." },
  { "id": 1045, "en": "rival", "ar": "منافس / خصم", "pronounce": "رَايْفَل", "ex_en": "His rival was the fastest in the race.", "ar_ex": "كان منافسُهُ الأسرعَ في السباقِ." },
  { "id": 1046, "en": "rob", "ar": "يسرق", "pronounce": "رُوب", "ex_en": "The thief robbed the bank at night.", "ar_ex": "سرقَ اللصُّ البنكَ ليلًا." },
  { "id": 1047, "en": "robbery", "ar": "سرقة", "pronounce": "رُوبَرِي", "ex_en": "A robbery took place in the neighborhood yesterday.", "ar_ex": "وقعتْ سرقةٌ في الحيِّ أمسِ." },
  { "id": 1048, "en": "rocket", "ar": "صاروخ", "pronounce": "رُوكِت", "ex_en": "The rocket launched into space.", "ar_ex": "انطلقَ الصاروخُ إلى الفضاءِ." },
  { "id": 1049, "en": "romance", "ar": "رومانسية / حب", "pronounce": "رُومَانْس", "ex_en": "The story is about love and romance.", "ar_ex": "تدورُ القصّةُ حولَ الحبِّ والرومانسيةِ." },
  { "id": 1050, "en": "root", "ar": "جذر", "pronounce": "رُوت", "ex_en": "The roots of the tree are very deep.", "ar_ex": "جذورُ الشجرةِ عميقةٌ جدًّا." },
  { "id": 1051, "en": "rose", "ar": "وردة", "pronounce": "رُوز", "ex_en": "He gave her a red rose.", "ar_ex": "أعطاها وردةً حمراءَ." },
  { "id": 1052, "en": "roughly", "ar": "تقريبًا / على نحو خشن", "pronounce": "رَفْلِي", "ex_en": "There are roughly twenty people here.", "ar_ex": "يوجدُ تقريبًا عشرونَ شخصًا هنا." },
  { "id": 1053, "en": "rub", "ar": "يفرك", "pronounce": "رَب", "ex_en": "He rubbed his hands because of the cold.", "ar_ex": "فركَ يدَيْهِ من البردِ." },
  { "id": 1054, "en": "rubber", "ar": "مطّاط", "pronounce": "رَبَر", "ex_en": "This ring was made of rubber.", "ar_ex": "صُنعَ هذا الخاتمُ من المطّاطِ." },
  { "id": 1055, "en": "ruin", "ar": "يُدمّر / يُفسد", "pronounce": "رُوِن", "ex_en": "The war ruined the old city.", "ar_ex": "دمّرَتِ الحربُ المدينةَ القديمةَ." },
  { "id": 1056, "en": "rural", "ar": "ريفي", "pronounce": "رُورَل", "ex_en": "Many people live in rural areas.", "ar_ex": "يعيشُ كثيرٌ من الناسِ في مناطقَ ريفيّةٍ." },
  { "id": 1057, "en": "rush", "ar": "يندفع / يسرع", "pronounce": "رَش", "ex_en": "He rushed to the door when he heard the sound.", "ar_ex": "هرعَ إلى البابِ عندَ سماعِ الصوتِ." },
  { "id": 1058, "en": "satellite", "ar": "قمر صناعي", "pronounce": "سَاتَلَايْت", "ex_en": "The satellite moves around the Earth.", "ar_ex": "يدورُ القمرُ الصناعيُّ حولَ الأرضِ." },
  { "id": 1059, "en": "satisfaction", "ar": "رضا / إشباع", "pronounce": "سَاتِسْفَاكْشَن", "ex_en": "I feel great satisfaction with the result.", "ar_ex": "أشعرُ برضا كبيرٍ عن النتيجةِ." },
  { "id": 1060, "en": "satisfied", "ar": "راضٍ", "pronounce": "سَاتِسْفَايْد", "ex_en": "He was satisfied with his performance.", "ar_ex": "كان راضيًا عن أدائِهِ." },
  { "id": 1061, "en": "satisfy", "ar": "يُرضي", "pronounce": "سَاتِسْفَاي", "ex_en": "This clear progress satisfies me.", "ar_ex": "يُرضيني هذا التقدّمُ الواضحُ." },
  { "id": 1062, "en": "scale", "ar": "مقياس / نطاق", "pronounce": "سْكَيْل", "ex_en": "The drawing grew larger on this scale.", "ar_ex": "ازدادَ حجمُ الرسمِ على هذا المقياسِ." },
  { "id": 1063, "en": "scandal", "ar": "فضيحة", "pronounce": "سْكَانْدَل", "ex_en": "The news caused a huge scandal.", "ar_ex": "أثارَ الخبرُ فضيحةً كبيرةً." },
  { "id": 1064, "en": "scare", "ar": "يُخيف", "pronounce": "سْكِير", "ex_en": "The sound scared the little child.", "ar_ex": "أخافَ الصوتُ الطفلَ الصغيرَ." },
  { "id": 1065, "en": "scholar", "ar": "باحث / عالِم", "pronounce": "سْكُولَر", "ex_en": "The scholar presented important research.", "ar_ex": "قدّمَ العالِمُ بحثًا مهمًّا." },
  { "id": 1066, "en": "scholarship", "ar": "منحة دراسية", "pronounce": "سْكُولَرْشِب", "ex_en": "He got a full scholarship.", "ar_ex": "حصلَ على منحةٍ دراسيّةٍ كاملةٍ." },
  { "id": 1067, "en": "scratch", "ar": "يخدش / يحكّ", "pronounce": "سْكْرَاتْش", "ex_en": "He scratched the table with the key.", "ar_ex": "خدشَ الطاولةَ بالمفتاحِ." },
  { "id": 1068, "en": "scream", "ar": "يصرخ", "pronounce": "سْكْرِيم", "ex_en": "She began to scream in fear.", "ar_ex": "بدأتْ تصرخُ من الخوفِ." },
  { "id": 1069, "en": "screening", "ar": "فحص / عرض", "pronounce": "سْكْرِينِنْغ", "ex_en": "The patient underwent early screening.", "ar_ex": "خضعَ المريضُ لفحصٍ مبكّرٍ." },
  { "id": 1070, "en": "sector", "ar": "قطاع", "pronounce": "سِكْتَر", "ex_en": "This sector is witnessing rapid growth.", "ar_ex": "يشهدُ هذا القطاعُ نموًّا سريعًا." },
  { "id": 1071, "en": "secure", "ar": "يؤمّن / يثبّت / يحصل على", "pronounce": "سِكْيُور", "ex_en": "We must secure the building well.", "ar_ex": "يجبُ أن نؤمّنَ المبنى جيدًا." },
  { "id": 1072, "en": "seek", "ar": "يسعى / يطلب", "pronounce": "سِيك", "ex_en": "He seeks a better life.", "ar_ex": "يسعى إلى حياةٍ أفضلَ." },
  { "id": 1073, "en": "seeker", "ar": "باحث / طالب", "pronounce": "سِيكَر", "ex_en": "The center helps job seekers.", "ar_ex": "يساعدُ المركزُ طالبي العملِ." },
  { "id": 1074, "en": "select", "ar": "يختار / ينتقي", "pronounce": "سِلِكْت", "ex_en": "The committee selected the best design.", "ar_ex": "اختارتِ اللجنةُ أفضلَ تصميمٍ." },
  { "id": 1075, "en": "selection", "ar": "اختيار / انتقاء", "pronounce": "سِلِكْشَن", "ex_en": "The selection was difficult this time.", "ar_ex": "كان الاختيارُ صعبًا هذه المرّةَ." },
  { "id": 1076, "en": "self", "ar": "الذات / النفس", "pronounce": "سِلْف", "ex_en": "A person must understand the self.", "ar_ex": "على الإنسانِ أن يفهمَ ذاتَهُ." },
  { "id": 1077, "en": "seminar", "ar": "ندوة", "pronounce": "سِمِنَار", "ex_en": "I attended a seminar about technology.", "ar_ex": "حضرتُ ندوةً عن التكنولوجيا." },
  { "id": 1078, "en": "senior", "ar": "أكبر / أقدم", "pronounce": "سِينْيَر", "ex_en": "My senior brother works in this company.", "ar_ex": "يعملُ أخي الأكبرُ في هذه الشركةِ." },
  { "id": 1079, "en": "sensitive", "ar": "حسّاس", "pronounce": "سِنْسِتِف", "ex_en": "His skin is very sensitive.", "ar_ex": "بشرتُهُ حسّاسةٌ جدًّا." },
  { "id": 1080, "en": "sequence", "ar": "تسلسل", "pronounce": "سِيكْوِنْس", "ex_en": "He followed the events in the correct sequence.", "ar_ex": "اتّبعَ الأحداثَ بالتسلسلِ الصحيحِ." },
  { "id": 1081, "en": "session", "ar": "جلسة", "pronounce": "سِشَن", "ex_en": "The session lasted two full hours.", "ar_ex": "استمرّتِ الجلسةُ ساعتينِ كاملتينِ." },
  { "id": 1082, "en": "settle", "ar": "يستقر / يُسوّي", "pronounce": "سِتُل", "ex_en": "The family settled in the new city.", "ar_ex": "استقرّتِ العائلةُ في المدينةِ الجديدةِ." },
  { "id": 1083, "en": "settler", "ar": "مستوطن", "pronounce": "سِتْلَر", "ex_en": "The settler arrived at the new land.", "ar_ex": "وصلَ المستوطنُ إلى الأرضِ الجديدةِ." },
  { "id": 1084, "en": "severe", "ar": "شديد / قاسٍ", "pronounce": "سِفِير", "ex_en": "The storm was severe and dangerous.", "ar_ex": "كانتِ العاصفةُ شديدةً وخطيرةً." },
  { "id": 1085, "en": "severely", "ar": "بشدّة", "pronounce": "سِفِيرْلِي", "ex_en": "The city was severely damaged.", "ar_ex": "تضرّرَتِ المدينةُ بشدّةٍ." },
  { "id": 1086, "en": "sexy", "ar": "مثير", "pronounce": "سِكْسِي", "ex_en": "This advertisement was bold and sexy.", "ar_ex": "كان هذا الإعلانُ جريئًا وغيرَ لائقٍ." },
  { "id": 1087, "en": "shade", "ar": "ظلّ / درجة لونية", "pronounce": "شَيْد", "ex_en": "They sat in the shade of a big tree.", "ar_ex": "جلسوا في ظلِّ شجرةٍ كبيرةٍ." },
  { "id": 1088, "en": "shadow", "ar": "ظل", "pronounce": "شَادُو", "ex_en": "His shadow appeared on the wall.", "ar_ex": "ظهرَ ظلُّهُ على الجدارِ." },
  { "id": 1089, "en": "shallow", "ar": "ضحل", "pronounce": "شَالُو", "ex_en": "The water was shallow near the shore.", "ar_ex": "كان الماءُ ضحلًا قربَ الشاطئِ." },
  { "id": 1090, "en": "shame", "ar": "خجل / عار", "pronounce": "شَيْم", "ex_en": "He felt shame for his behavior.", "ar_ex": "شعرَ بالخجلِ من تصرّفِهِ." },
  { "id": 1091, "en": "shaped", "ar": "مُشكَّل / ذو شكل", "pronounce": "شَيْبْت", "ex_en": "The cloud was heart-shaped.", "ar_ex": "كانت السحابةُ على شكلِ قلبٍ." },
  { "id": 1092, "en": "shelter", "ar": "مأوى / ملجأ", "pronounce": "شِلْتَر", "ex_en": "They provided shelter for those in need.", "ar_ex": "وفّروا مأوى للمحتاجينَ." },
  { "id": 1093, "en": "shooting", "ar": "إطلاق نار", "pronounce": "شُوتِنْغ", "ex_en": "We heard about a shooting in the neighborhood.", "ar_ex": "سمعنا خبرَ إطلاقِ النارِ في الحيِّ." },
  { "id": 1094, "en": "shore", "ar": "شاطئ", "pronounce": "شُور", "ex_en": "She sat near the shore at sunset.", "ar_ex": "جلسَتْ قربَ الشاطئِ عند الغروبِ." },
  { "id": 1095, "en": "short-term", "ar": "قصير الأمد", "pronounce": "شُورْت تِرْم", "ex_en": "We need a short-term solution now.", "ar_ex": "نحتاجُ إلى حلٍّ قصيرِ الأمدِ الآنَ." },
  { "id": 1096, "en": "shortage", "ar": "نقص / عجز", "pronounce": "شُورْتِج", "ex_en": "The city suffers from a water shortage.", "ar_ex": "تعاني المدينةُ من نقصٍ في المياهِ." },
  { "id": 1097, "en": "shortly", "ar": "بعد قليل / قريبًا", "pronounce": "شُورْتْلِي", "ex_en": "The train will arrive shortly.", "ar_ex": "سيصلُ القطارُ بعدَ قليلٍ." },
  { "id": 1098, "en": "sibling", "ar": "شقيق / أخت أو أخ", "pronounce": "سِبْلِنْغ", "ex_en": "I have one brother and two sisters, so I have three siblings.", "ar_ex": "لديَّ أخٌ واحدٌ وأختانِ، أي ثلاثةُ أشقّاءَ." },
  { "id": 1099, "en": "sidewalk", "ar": "رصيف", "pronounce": "سَايْدْوُوك", "ex_en": "I walked on the sidewalk to the end of the street.", "ar_ex": "مشيتُ على الرصيفِ حتى آخرِ الشارعِ." },
  { "id": 1100, "en": "signature", "ar": "توقيع", "pronounce": "سِغْنَتْشَر", "ex_en": "She wrote her signature at the bottom of the letter.", "ar_ex": "وقّعتْ باسمِها في أسفلِ الرسالةِ." },
  { "id": 1101, "en": "significance", "ar": "أهمية / دلالة", "pronounce": "سِغْنِفِكَنْس", "ex_en": "The significance of the decision was great.", "ar_ex": "كانت أهميةُ القرارِ كبيرةً." },
  { "id": 1102, "en": "significant", "ar": "مهم / ذو دلالة", "pronounce": "سِغْنِفِكَنْت", "ex_en": "It was a significant change in his life.", "ar_ex": "كان تغيّرًا مهمًّا في حياتِهِ." },
  { "id": 1103, "en": "significantly", "ar": "بشكلٍ ملحوظ", "pronounce": "سِغْنِفِكَنْتْلِي", "ex_en": "The population decreased significantly.", "ar_ex": "انخفضَ عددُ السكّانِ بشكلٍ ملحوظٍ." },
  { "id": 1104, "en": "silence", "ar": "صمت", "pronounce": "سَايْلَنْس", "ex_en": "Silence filled the room.", "ar_ex": "سادَ الصمتُ في الغرفةِ." },
  { "id": 1105, "en": "silk", "ar": "حرير", "pronounce": "سِلْك", "ex_en": "The dress was made of silk.", "ar_ex": "صُنِعَ الفستانُ من الحريرِ." },
  { "id": 1106, "en": "sincere", "ar": "صادق / مخلص", "pronounce": "سِنْسِير", "ex_en": "He gave a sincere apology.", "ar_ex": "قدّمَ اعتذارًا صادقًا." },
  { "id": 1107, "en": "skilled", "ar": "ماهر", "pronounce": "سْكِلْد", "ex_en": "We need skilled workers.", "ar_ex": "نحتاجُ إلى عمّالٍ مهرةٍ." },
  { "id": 1108, "en": "skull", "ar": "جمجمة", "pronounce": "سْكَال", "ex_en": "The skull appeared in the picture.", "ar_ex": "ظهرتِ الجمجمةُ في الصورةِ." },
  { "id": 1109, "en": "slave", "ar": "عبد", "pronounce": "سْلَيْف", "ex_en": "They fought the slave trade.", "ar_ex": "حاربوا تجارةَ العبيدِ." },
  { "id": 1110, "en": "slide", "ar": "ينزلق", "pronounce": "سْلَايْد", "ex_en": "The paper began to slide from my hands.", "ar_ex": "انزلقتِ الورقةُ من بينِ يدي." },
  { "id": 1111, "en": "slight", "ar": "طفيف / بسيط", "pronounce": "سْلَايْت", "ex_en": "There was a slight difference between the two prices.", "ar_ex": "كان هناكَ فرقٌ بسيطٌ بينَ السعرينِ." },
  { "id": 1112, "en": "slip", "ar": "ينزلق / يفلت", "pronounce": "سْلِب", "ex_en": "His foot slipped on the wet floor.", "ar_ex": "انزلقتْ قدمُهُ على الأرضِ المبلّلةِ." },
  { "id": 1113, "en": "slogan", "ar": "شعار", "pronounce": "سْلُوغَن", "ex_en": "The slogan was easy to remember.", "ar_ex": "كان الشعارُ سهلَ الحفظِ." },
  { "id": 1114, "en": "slope", "ar": "منحدر", "pronounce": "سْلُوب", "ex_en": "They climbed the slope slowly.", "ar_ex": "صعدوا المنحدرَ ببطءٍ." },
  { "id": 1115, "en": "so-called", "ar": "ما يسمّى بـ", "pronounce": "سُو كُولْد", "ex_en": "The so-called quick solution is not always the best.", "ar_ex": "ما يسمّى بالحلِّ السريعِ ليس دائمًا الأفضلَ." },
  { "id": 1116, "en": "solar", "ar": "شمسي", "pronounce": "سُولَر", "ex_en": "These houses depend on solar energy.", "ar_ex": "تعتمدُ هذه البيوتُ على الطاقةِ الشمسيّةِ." },
  { "id": 1117, "en": "somehow", "ar": "بطريقةٍ ما", "pronounce": "سَمْهَاو", "ex_en": "Somehow, we found the solution.", "ar_ex": "بطريقةٍ ما، وجدنا الحلَّ." },
  { "id": 1118, "en": "sometime", "ar": "في وقتٍ ما", "pronounce": "سَمْتَايْم", "ex_en": "Come here sometime tomorrow.", "ar_ex": "تعالَ إلى هنا في وقتٍ ما غدًا." },
  { "id": 1119, "en": "somewhat", "ar": "نوعًا ما / إلى حدٍّ ما", "pronounce": "سَمْوَات", "ex_en": "The weather was somewhat cold.", "ar_ex": "كان الجوُّ باردًا نوعًا ما." },
  { "id": 1120, "en": "sophisticated", "ar": "راقٍ / متطوّر / معقّد", "pronounce": "سَفِسْتِكَيْتِد", "ex_en": "The city was sophisticated and advanced.", "ar_ex": "كانتْ المدينةُ راقيةً ومتطوّرةً." },
  { "id": 1121, "en": "soul", "ar": "روح", "pronounce": "سُول", "ex_en": "She believes that the soul is eternal.", "ar_ex": "تؤمنُ بأنّ الروحَ خالدةٌ." },
  { "id": 1122, "en": "source", "ar": "مصدر", "pronounce": "سُورْس", "ex_en": "This source is very reliable.", "ar_ex": "هذا المصدرُ موثوقٌ جدًّا." },
  { "id": 1123, "en": "spare", "ar": "إضافي / احتياطي", "pronounce": "سْبِير", "ex_en": "I have a spare room for guests.", "ar_ex": "لديَّ غرفةٌ إضافيّةٌ للضيوفِ." },
  { "id": 1124, "en": "specialise", "ar": "يتخصّص", "pronounce": "سْبِشَلَايْز", "ex_en": "He specialised in heart surgery.", "ar_ex": "تخصّصَ في جراحةِ القلبِ." },
  { "id": 1125, "en": "specialist", "ar": "أخصائي / مختص", "pronounce": "سْبِشَلِسْت", "ex_en": "We need a specialist doctor.", "ar_ex": "نحتاجُ إلى طبيبٍ مختصٍّ." },
  { "id": 1126, "en": "species", "ar": "نوع / فصيلة", "pronounce": "سْبِيشِيز", "ex_en": "This species of birds is rare.", "ar_ex": "هذا النوعُ من الطيورِ نادرٌ." },
  { "id": 1127, "en": "specify", "ar": "يحدّد / يوضّح بدقّة", "pronounce": "سْبِسِفَاي", "ex_en": "Specify exactly what you need.", "ar_ex": "حدّدْ ما تحتاجُهُ بالضبطِ." },
  { "id": 1128, "en": "spectacular", "ar": "مذهل / رائع جدًا", "pronounce": "سْبِكْتَاكْيُولَر", "ex_en": "The show was spectacular.", "ar_ex": "كان العرضُ مذهلًا بحقٍّ." },
  { "id": 1129, "en": "spectator", "ar": "متفرّج", "pronounce": "سْبِكْتَيْتَر", "ex_en": "The spectators sat in silence.", "ar_ex": "جلسَ المتفرّجونَ في صمتٍ." },
  { "id": 1130, "en": "speculate", "ar": "يتكهّن / يضارب", "pronounce": "سْبِكْيُلَيْت", "ex_en": "People began to speculate about the cause.", "ar_ex": "بدأَ الناسُ يتكهّنونَ حولَ السببِ." },
  { "id": 1131, "en": "speculation", "ar": "تكهّنات / مضاربات", "pronounce": "سْبِكْيُلَيْشَن", "ex_en": "There was a lot of speculation in the newspapers.", "ar_ex": "كانتْ هناكَ تكهّناتٌ كثيرةٌ في الصحفِ." },
  { "id": 1132, "en": "spice", "ar": "بهار / نكهة", "pronounce": "سْبَايْس", "ex_en": "He added some spice to the food.", "ar_ex": "أضافَ بعضَ البهاراتِ إلى الطعامِ." },
  { "id": 1133, "en": "spill", "ar": "ينسكب / يريق", "pronounce": "سْبِل", "ex_en": "The water spilled on the table.", "ar_ex": "انسكبَ الماءُ على الطاولةِ." },
  { "id": 1134, "en": "spiritual", "ar": "روحاني", "pronounce": "سْبِرِتشُوَل", "ex_en": "He was spiritual by nature.", "ar_ex": "كان شخصًا روحانيًّا بطبعِهِ." },
  { "id": 1135, "en": "in spite of", "ar": "رغم / على الرغم من", "pronounce": "إِنْ سْبَايْت أُف", "ex_en": "In spite of the rain, we went for a walk.", "ar_ex": "رغمَ المطرِ، خرجنا للنزهةِ." },
  { "id": 1136, "en": "split", "ar": "ينقسم / يشقّ", "pronounce": "سْبْلِت", "ex_en": "The cake split into two halves.", "ar_ex": "انقسمتِ الكعكةُ إلى نصفينِ." },
  { "id": 1137, "en": "spoil", "ar": "يفسد", "pronounce": "سْبُويل", "ex_en": "The rain spoiled the trip.", "ar_ex": "أفسدَ المطرُ الرحلةَ." },
  { "id": 1138, "en": "spokesman", "ar": "متحدث رسمي", "pronounce": "سْبُوكْسْمَن", "ex_en": "The spokesman spoke to the media.", "ar_ex": "تحدّثَ المتحدّثُ الرسميُّ إلى الإعلامِ." },
  { "id": 1139, "en": "spokesperson", "ar": "متحدث رسمي", "pronounce": "سْبُوكْسْبِرْسَن", "ex_en": "The spokesperson thanked the team.", "ar_ex": "شكرتِ المتحدّثةُ الرسميّةُ الفريقَ." },
  { "id": 1140, "en": "sp spokeswoman", "ar": "متحدثة رسمية", "pronounce": "سْبُوكْسْوُمَن", "ex_en": "The spokeswoman appeared at the conference.", "ar_ex": "ظهرتِ المتحدّثةُ الرسميّةُ في المؤتمرِ." },
  { "id": 1141, "en": "sponsor", "ar": "راعٍ / يرعى", "pronounce": "سْبُونْسَر", "ex_en": "The company sponsored the event officially.", "ar_ex": "رعتِ الشركةُ الحدثَ رسميًّا." },
  { "id": 1142, "en": "sponsorship", "ar": "رعاية / تمويل دعائي", "pronounce": "سْبُونْسَرْشِب", "ex_en": "The sponsorship helped the festival succeed.", "ar_ex": "ساعدتِ الرعايةُ في نجاحِ المهرجانِ." },
  { "id": 1143, "en": "stable", "ar": "مستقر / ثابت", "pronounce": "سْتَيْبُل", "ex_en": "The situation remained stable for days.", "ar_ex": "بقيَ الوضعُ مستقرًّا لأيامٍ." },
  { "id": 1144, "en": "stall", "ar": "كشك / موقف", "pronounce": "سْتُول", "ex_en": "There was a small stall in the market.", "ar_ex": "كان هناكَ كشكٌ صغيرٌ في السوقِ." },
  { "id": 1145, "en": "stance", "ar": "موقف / وجهة نظر", "pronounce": "سْتَانْس", "ex_en": "He explained his stance in the session.", "ar_ex": "أوضحَ موقفَهُ في الجلسةِ." },
  { "id": 1146, "en": "stare", "ar": "يحدّق", "pronounce": "سْتِير", "ex_en": "He continued to stare at the picture for a long time.", "ar_ex": "ظلَّ يحدّقُ في الصورةِ طويلًا." },
  { "id": 1147, "en": "starve", "ar": "يتضوّر جوعًا", "pronounce": "سْتَارْف", "ex_en": "People were about to starve from hunger.", "ar_ex": "كادَ الناسُ يموتونَ من الجوعِ." },
  { "id": 1148, "en": "statistic", "ar": "إحصائية / رقم إحصائي", "pronounce": "سْتَتِسْتِك", "ex_en": "The statistic shows a slight increase.", "ar_ex": "تشيرُ الإحصائيةُ إلى ارتفاعٍ طفيفٍ." },
  { "id": 1149, "en": "status", "ar": "وضع / حالة / مكانة", "pronounce": "سْتَيْتَس", "ex_en": "His status is still unclear.", "ar_ex": "ما زالَ وضعُهُ غيرَ واضحٍ." },
  { "id": 1150, "en": "steadily", "ar": "باطراد / بثبات", "pronounce": "سْتِيدِلِي", "ex_en": "The economy improved steadily.", "ar_ex": "تحسّنَ الاقتصادُ باطرادٍ." },
  { "id": 1151, "en": "steady", "ar": "ثابت / مستقر", "pronounce": "سْتِيدِي", "ex_en": "His hand remained steady.", "ar_ex": "ظلَّتْ يدُهُ ثابتةً." },
  { "id": 1152, "en": "steam", "ar": "بخار", "pronounce": "سْتِيم", "ex_en": "Steam rose from the cup.", "ar_ex": "تصاعدَ البخارُ من الكوبِ." },
  { "id": 1153, "en": "steel", "ar": "فولاذ", "pronounce": "سْتِيل", "ex_en": "The bridge is made of steel.", "ar_ex": "الجسرُ مصنوعٌ من الفولاذِ." },
  { "id": 1154, "en": "steep", "ar": "شديد الانحدار / حاد", "pronounce": "سْتِيب", "ex_en": "The road was steep.", "ar_ex": "كان الطريقُ شديدَ الانحدارِ." },
  { "id": 1155, "en": "sticky", "ar": "لزج", "pronounce": "سْتِكِي", "ex_en": "My hands were sticky with honey.", "ar_ex": "كانتْ يدايَ لزجتينِ من العسلِ." },
  { "id": 1156, "en": "stiff", "ar": "صلب / قاسٍ / متيبّس", "pronounce": "سْتِف", "ex_en": "The fabric was stiff and hard.", "ar_ex": "كان القماشُ قاسيًا وصلبًا." },
  { "id": 1157, "en": "stimulate", "ar": "يُحفّز / ينشّط", "pronounce": "سْتِمْيُلَيْت", "ex_en": "Exercise stimulates brain activity.", "ar_ex": "تُحفّزُ الرياضةُ نشاطَ الدماغِ." },
  { "id": 1158, "en": "stock", "ar": "سهم / مخزون", "pronounce": "سْتُوك", "ex_en": "He invested in the stock market.", "ar_ex": "استثمرَ في سوقِ الأسهمِ." },
  { "id": 1159, "en": "stream", "ar": "جدول / تيّار", "pronounce": "سْتْرِيم", "ex_en": "A small stream runs near the house.", "ar_ex": "يمرُّ جدولٌ صغيرٌ قربَ البيتِ." },
  { "id": 1160, "en": "strengthen", "ar": "يقوّي / يعزّز", "pronounce": "سْتْرِنْغْثَن", "ex_en": "We must strengthen our relationship.", "ar_ex": "يجبُ أن نقوّيَ علاقتَنا." },
  { "id": 1161, "en": "stretch", "ar": "يمدّ / يتمدّد", "pronounce": "سْتْرِتْش", "ex_en": "He stretched his arm to take the book.", "ar_ex": "مدَّ ذراعَهُ ليلتقطَ الكتابَ." },
  { "id": 1162, "en": "strict", "ar": "صارم", "pronounce": "سْتْرِكْت", "ex_en": "The school was strict in its rules.", "ar_ex": "كانتِ المدرسةُ صارمةً في قوانينِها." },
  { "id": 1163, "en": "strictly", "ar": "بشكلٍ صارم", "pronounce": "سْتْرِكْتْلِي", "ex_en": "Smoking is strictly forbidden here.", "ar_ex": "يُمنَعُ التدخينُ منعًا باتًّا هنا." },
  { "id": 1164, "en": "strike", "ar": "إضراب / يضرب", "pronounce": "سْتْرَايْك", "ex_en": "The strike began on Monday morning.", "ar_ex": "بدأَ الإضرابُ صباحَ الاثنينِ." },
  { "id": 1165, "en": "striking", "ar": "لافت / مدهش", "pronounce": "سْتْرَايْكِنْغ", "ex_en": "Her appearance was striking.", "ar_ex": "كان منظرُها لافتًا للنظرِ." },
  { "id": 1166, "en": "stroke", "ar": "جلطة / سكتة دماغية", "pronounce": "سْتْرُوك", "ex_en": "He had a mild stroke.", "ar_ex": "أُصيبَ بجلطةٍ خفيفةٍ." },
  { "id": 1167, "en": "struggle", "ar": "يكافح / يصارع", "pronounce": "سْتْرَغُل", "ex_en": "He struggled for a long time to succeed.", "ar_ex": "كافحَ طويلًا من أجلِ النجاحِ." },
  { "id": 1168, "en": "stunning", "ar": "مذهل / رائع جدًا", "pronounce": "سْتَنِنْغ", "ex_en": "The view was stunning.", "ar_ex": "كان المشهدُ مذهلًا حقًّا." },
  { "id": 1169, "en": "submit", "ar": "يقدّم / يرسل رسميًّا", "pronounce": "سَبْمِت", "ex_en": "He submitted the application before the deadline.", "ar_ex": "قدّمَ الطلبَ قبلَ الموعدِ." },
  { "id": 1170, "en": "substance", "ar": "مادّة / جوهر", "pronounce": "سَبْسْتَنْس", "ex_en": "This substance must be analyzed carefully.", "ar_ex": "يجبُ تحليلُ هذه المادّةِ بعنايةٍ." },
  { "id": 1171, "en": "suburb", "ar": "ضاحية", "pronounce": "سَبِرْب", "ex_en": "They live in a quiet suburb.", "ar_ex": "يسكنونَ في ضاحيةٍ هادئةٍ." },
  { "id": 1172, "en": "suffering", "ar": "معاناة", "pronounce": "سَفَرِنْغ", "ex_en": "The pain caused long suffering.", "ar_ex": "كان الألمُ شديدًا ومعهُ معاناةٌ طويلةٌ." },
  { "id": 1173, "en": "sufficient", "ar": "كافٍ", "pronounce": "سَفِشَنْت", "ex_en": "This amount is sufficient to buy the book.", "ar_ex": "هذا المبلغُ كافٍ لشراءِ الكتابِ." },
  { "id": 1174, "en": "sufficiently", "ar": "بشكلٍ كافٍ", "pronounce": "سَفِشَنْتْلِي", "ex_en": "The explanation was sufficiently clear.", "ar_ex": "كان الشرحُ واضحًا بما يكفي." },
  { "id": 1175, "en": "sum", "ar": "مجموع", "pronounce": "سَم", "ex_en": "Calculate the sum of these numbers.", "ar_ex": "احسبْ مجموعَ هذه الأرقامِ." },
  { "id": 1176, "en": "super", "ar": "رائع / ممتاز", "pronounce": "سُوبَر", "ex_en": "The show was super.", "ar_ex": "كان العرضُ رائعًا للغايةِ." },
  { "id": 1177, "en": "surgeon", "ar": "جرّاح", "pronounce": "سِرْجَن", "ex_en": "The surgeon performed the operation successfully.", "ar_ex": "أجرى الجرّاحُ العمليّةَ بنجاحٍ." },
  { "id": 1178, "en": "surgery", "ar": "جراحة / عمليّة جراحيّة", "pronounce": "سِرْجَرِي", "ex_en": "He needs urgent surgery.", "ar_ex": "تحتاجُ إلى جراحةٍ عاجلةٍ." },
  { "id": 1179, "en": "surround", "ar": "يحيط بـ", "pronounce": "سَرَاوْنْد", "ex_en": "Trees surrounded the house.", "ar_ex": "أحاطتِ الأشجارُ بالبيتِ." },
  { "id": 1180, "en": "surrounding", "ar": "محيط / مجاور", "pronounce": "سَرَاوْنْدِنْغ", "ex_en": "The surrounding villages were affected by the storm.", "ar_ex": "تأثّرتِ القرى المحيطةُ بالعاصفةِ." },
  { "id": 1181, "en": "survival", "ar": "بقاء / نجاة", "pronounce": "سَرْفَايْفَل", "ex_en": "Survival was difficult.", "ar_ex": "كانتْ مسألةُ البقاءِ صعبةً." },
  { "id": 1182, "en": "survivor", "ar": "ناجٍ", "pronounce": "سَرْفَايْفَر", "ex_en": "The survivor spoke about what happened.", "ar_ex": "تحدّثَ الناجي عمّا حدثَ." },
  { "id": 1183, "en": "suspect", "ar": "مشتبه به / يشتبه", "pronounce": "سَسْبِكْت", "ex_en": "The police suspect an unknown man.", "ar_ex": "تشتبهُ الشرطةُ في رجلٍ مجهولٍ." },
  { "id": 1184, "en": "suspend", "ar": "يعلّق / يوقف مؤقتًا", "pronounce": "سَسْبِينْد", "ex_en": "The company suspended work temporarily.", "ar_ex": "علّقتِ الشركةُ العملَ مؤقّتًا." },
  { "id": 1185, "en": "sustainability", "ar": "استدامة", "pronounce": "سَسْتَيْنَبِلِتِي", "ex_en": "Sustainability has become a global goal.", "ar_ex": "أصبحتِ الاستدامةُ هدفًا عالميًّا." },
  { "id": 1186, "en": "sustainable", "ar": "مستدام", "pronounce": "سَسْتَيْنَبُل", "ex_en": "We need sustainable solutions.", "ar_ex": "نحتاجُ إلى حلولٍ مستدامةٍ." },
  { "id": 1187, "en": "swallow", "ar": "يبتلع", "pronounce": "سْوَالُو", "ex_en": "The child swallowed the medicine quickly.", "ar_ex": "ابتلعَ الطفلُ الدواءَ بسرعةٍ." },
  { "id": 1188, "en": "swear", "ar": "يقسم / يشتم", "pronounce": "سْوِير", "ex_en": "He swore that he was telling the truth.", "ar_ex": "أقسمَ أنّهُ يقولُ الحقيقةَ." },
  { "id": 1189, "en": "sweep", "ar": "يكنس", "pronounce": "سْوِيب", "ex_en": "He swept the floor before the guests arrived.", "ar_ex": "كنسَ الأرضَ قبلَ الضيوفِ." },
  { "id": 1190, "en": "symbol", "ar": "رمز", "pronounce": "سِمْبُل", "ex_en": "The dove is a symbol of peace.", "ar_ex": "الحمامةُ رمزٌ للسلامِ." },
  { "id": 1191, "en": "symbolise", "ar": "يرمز إلى", "pronounce": "سِمْبُلَايْز", "ex_en": "The white color symbolises purity.", "ar_ex": "يرمزُ اللونُ الأبيضُ إلى النقاءِ." },
  { "id": 1192, "en": "sympathetic", "ar": "متعاطف / متفهّم", "pronounce": "سِمْبَثِتِك", "ex_en": "She was sympathetic to her friend.", "ar_ex": "كانتْ متعاطفةً مع صديقتِها." },
  { "id": 1193, "en": "sympathy", "ar": "تعاطف", "pronounce": "سِمْبَثِي", "ex_en": "He expressed his sympathy with the victims.", "ar_ex": "عبّرَ عن تعاطفِهِ مع المتضرّرينَ." },
  { "id": 1194, "en": "tag", "ar": "بطاقة / يضع بطاقة", "pronounce": "تَاغ", "ex_en": "He attached a tag to the bag.", "ar_ex": "علّقَ بطاقةً على الحقيبةِ." },
  { "id": 1195, "en": "tale", "ar": "حكاية", "pronounce": "تَيْل", "ex_en": "Grandmother told an old tale.", "ar_ex": "حكتِ الجدّةُ حكايةً قديمةً." },
  { "id": 1196, "en": "tank", "ar": "خزّان / دبابة", "pronounce": "تَانْك", "ex_en": "The tank was almost empty.", "ar_ex": "كان الخزّانُ فارغًا تقريبًا." },
  { "id": 1197, "en": "tap", "ar": "صنبور / ينقر", "pronounce": "تَاب", "ex_en": "She turned on the tap to wash her hands.", "ar_ex": "فتحتِ الصنبورَ لغسلِ يديها." },
  { "id": 1198, "en": "tear", "ar": "دمعة / يمزّق", "pronounce": "تِير", "ex_en": "A tear fell from her eye.", "ar_ex": "سالتْ دمعةٌ من عينِها." },
  { "id": 1199, "en": "technological", "ar": "تكنولوجي", "pronounce": "تِكْنَلُوجِكَل", "ex_en": "The world witnessed great technological progress.", "ar_ex": "شهدَ العالمُ تقدّمًا تكنولوجيًّا هائلًا." },
  { "id": 1200, "en": "teen", "ar": "مراهق", "pronounce": "تِين", "ex_en": "He behaves like teens sometimes.", "ar_ex": "يتصرّفُ كالمراهقينَ أحيانًا." },
  { "id": 1201, "en": "temple", "ar": "معبد", "pronounce": "تِمْبُل", "ex_en": "They visited an old temple in the mountain.", "ar_ex": "زاروا معبدًا قديمًا في الجبلِ." },
  { "id": 1202, "en": "temporarily", "ar": "مؤقّتًا", "pronounce": "تِمْبُرِرِلِي", "ex_en": "The office was closed temporarily.", "ar_ex": "أُغلِقَ المكتبُ مؤقّتًا." },
  { "id": 1203, "en": "temporary", "ar": "مؤقّت", "pronounce": "تِمْبُرِرِي", "ex_en": "This is only a temporary solution.", "ar_ex": "هذا حلٌّ مؤقّتٌ فقط." },
  { "id": 1204, "en": "tendency", "ar": "ميل / نزعة", "pronounce": "تِنْدَنْسِي", "ex_en": "He has a tendency to be late.", "ar_ex": "لديهِ ميلٌ دائمٌ إلى التأخّرِ." },
  { "id": 1205, "en": "tension", "ar": "توتّر", "pronounce": "تِنْشَن", "ex_en": "There was tension in the atmosphere.", "ar_ex": "كان هناكَ توتّرٌ في الجوِّ." },
  { "id": 1206, "en": "terminal", "ar": "محطة / نهائي / طرفي", "pronounce": "تِرْمِنَل", "ex_en": "Wait for me at the main airport terminal.", "ar_ex": "انتظرني عندَ مبنى المطارِ الرئيسيِّ." },
  { "id": 1207, "en": "terms", "ar": "شروط / مصطلحات", "pronounce": "تِرْمْز", "ex_en": "We must agree on the terms first.", "ar_ex": "يجبُ الاتفاقُ على الشروطِ أولًا." },
  { "id": 1208, "en": "terribly", "ar": "بشدّة / جدًا", "pronounce": "تِرَبْلِي", "ex_en": "I felt terribly tired after the trip.", "ar_ex": "شعرتُ بتعبٍ شديدٍ بعدَ الرحلةِ." },
  { "id": 1209, "en": "terrify", "ar": "يُرعِب", "pronounce": "تِرِفَاي", "ex_en": "The bad news terrified them.", "ar_ex": "خوّفَهم الخبرُ السيّئُ." },
  { "id": 1210, "en": "territory", "ar": "إقليم / أرض", "pronounce": "تِرِتُورِي", "ex_en": "They defended their territory with all their strength.", "ar_ex": "دافعوا عن أراضيهم بكلِّ قوّةٍ." },
  { "id": 1211, "en": "terror", "ar": "رعب", "pronounce": "تِرَر", "ex_en": "Terror was clear in their eyes.", "ar_ex": "كان الرعبُ واضحًا في عيونِهم." },
  { "id": 1212, "en": "terrorism", "ar": "إرهاب", "pronounce": "تِرَرِزَم", "ex_en": "The world fights terrorism together.", "ar_ex": "يحاربُ العالمُ الإرهابَ معًا." },
  { "id": 1213, "en": "terrorist", "ar": "إرهابي", "pronounce": "تِرَرِسْت", "ex_en": "The police arrested the terrorist.", "ar_ex": "ألقتِ الشرطةُ القبضَ على الإرهابيِّ." },
  { "id": 1214, "en": "testing", "ar": "اختبار / فحص", "pronounce": "تِسْتِنْغ", "ex_en": "We are still in the testing stage.", "ar_ex": "ما زلنا في مرحلةِ الاختبارِ." },
  { "id": 1215, "en": "textbook", "ar": "كتاب مدرسي", "pronounce": "تِكْسْتْبُوك", "ex_en": "This textbook is very useful.", "ar_ex": "هذا الكتابُ المدرسيُّ مفيدٌ جدًا." },
  { "id": 1216, "en": "theft", "ar": "سرقة", "pronounce": "ثِفْت", "ex_en": "The shop was a victim of theft at night.", "ar_ex": "تعرّضَ المتجرُ لسرقةٍ ليلًا." },
  { "id": 1217, "en": "therapist", "ar": "معالِج نفسي", "pronounce": "ثِرَبِسْت", "ex_en": "The therapist advised me to rest.", "ar_ex": "نصحَني المعالِجُ النفسيُّ بالراحةِ." },
  { "id": 1218, "en": "therapy", "ar": "علاج", "pronounce": "ثِرَبِي", "ex_en": "Some cases need ongoing therapy.", "ar_ex": "تحتاجُ بعضُ الحالاتِ إلى علاجٍ مستمرٍّ." },
  { "id": 1219, "en": "theory", "ar": "نظرية", "pronounce": "ثِيُورِي", "ex_en": "This theory needs evidence.", "ar_ex": "هذه النظريةُ تحتاجُ إلى دليلٍ." },
  { "id": 1220, "en": "therefore", "ar": "لذلك / ولهذا", "pronounce": "ذِيرْفُور", "ex_en": "The train was late; therefore, I went back home.", "ar_ex": "تأخّرَ القطارُ، لذلكَ عدتُ إلى البيتِ." },
  { "id": 1221, "en": "thorough", "ar": "شامل / دقيق", "pronounce": "ثَرُو", "ex_en": "He made a thorough inspection of the house.", "ar_ex": "أجرى فحصًا شاملًا للبيتِ." },
  { "id": 1222, "en": "thoroughly", "ar": "تمامًا / بعناية شديدة", "pronounce": "ثَرُلِي", "ex_en": "She cleaned the room thoroughly.", "ar_ex": "نظّفتِ الغرفةَ تنظيفًا كاملًا." },
  { "id": 1223, "en": "threat", "ar": "تهديد", "pronounce": "ثْرِت", "ex_en": "There is a real threat to security.", "ar_ex": "هناكَ تهديدٌ حقيقيٌّ للأمنِ." },
  { "id": 1224, "en": "threaten", "ar": "يهدّد", "pronounce": "ثْرِتَنْ", "ex_en": "The man threatened the neighbor loudly.", "ar_ex": "هدّدَ الرجلُ الجارَ بصوتٍ عالٍ." },
  { "id": 1225, "en": "thumb", "ar": "إبهام", "pronounce": "ثَمْب", "ex_en": "She raised her thumb as a sign of approval.", "ar_ex": "رفعتِ إبهامَها علامةَ موافقةٍ." },
  { "id": 1226, "en": "thus", "ar": "وهكذا / لذلك", "pronounce": "ذَس", "ex_en": "The meeting ended quickly.", "ar_ex": "هكذا، انتهى الاجتماعُ بسرعةٍ." },
  { "id": 1227, "en": "timing", "ar": "توقيت", "pronounce": "تَايْمِنْغ", "ex_en": "Your timing was perfect.", "ar_ex": "كان توقيتُكَ مثاليًّا." },
  { "id": 1228, "en": "tissue", "ar": "نسيج / منديل ورقي", "pronounce": "تِشُو", "ex_en": "The doctor needed a tissue sample.", "ar_ex": "احتاجَ الطبيبُ إلى عيّنةِ نسيجٍ." },
  { "id": 1229, "en": "tone", "ar": "نبرة / لهجة", "pronounce": "تُن", "ex_en": "I did not like his tone of voice.", "ar_ex": "لم يعجبني نبرةُ صوتِهِ." },
  { "id": 1230, "en": "tough", "ar": "صعب / قوي / قاسٍ", "pronounce": "تَف", "ex_en": "The match was really tough.", "ar_ex": "كانتِ المباراةُ صعبةً جدًا." },
  { "id": 1231, "en": "tournament", "ar": "بطولة", "pronounce": "تُورْنَمَنْت", "ex_en": "The tournament is held every summer.", "ar_ex": "تُقامُ البطولةُ كلَّ صيفٍ." },
  { "id": 1232, "en": "toxic", "ar": "سام", "pronounce": "تُوكْسِك", "ex_en": "Some waste contains toxic materials.", "ar_ex": "تحتوي بعضُ النفاياتِ على موادَّ سامّةٍ." },
  { "id": 1233, "en": "trace", "ar": "أثر / يتتبّع", "pronounce": "تْرَيْس", "ex_en": "The police found a trace at the scene.", "ar_ex": "وجدَتِ الشرطةُ أثرًا في المكانِ." },
  { "id": 1234, "en": "track", "ar": "مسار / يتتبّع", "pronounce": "تْرَاك", "ex_en": "The shipment through the app.", "ar_ex": "علينا تتبّعُ الشحنةِ عبرَ التطبيقِ." },
  { "id": 1235, "en": "trading", "ar": "تجارة / تداول", "pronounce": "تْرَيْدِنْغ", "ex_en": "He has worked in trading for years.", "ar_ex": "تعملُ في مجالِ التجارةِ منذُ سنواتٍ." },
  { "id": 1236, "en": "tragedy", "ar": "مأساة", "pronounce": "تْرَاجِدِي", "ex_en": "The accident was a real tragedy.", "ar_ex": "كانتْ الحادثةُ مأساةً حقيقيّةً." },
  { "id": 1237, "en": "tragic", "ar": "مأساوي", "pronounce": "تْرَاجِك", "ex_en": "The end of the story was tragic.", "ar_ex": "كانت نهايةُ القصّةِ مأساويّةً." },
  { "id": 1238, "en": "trait", "ar": "صفة / سِمة", "pronounce": "تْرَيْت", "ex_en": "Patience is a beautiful trait in a person.", "ar_ex": "الصبرُ صفةٌ جميلةٌ في الإنسانِ." },
  { "id": 1239, "en": "transfer", "ar": "تحويل / ينقل", "pronounce": "تْرَانْسْفَر", "ex_en": "The transfer took several minutes.", "ar_ex": "استغرقَ التحويلُ عدّةَ دقائقَ." },
  { "id": 1240, "en": "transform", "ar": "يحوّل / يغيّر جذريًّا", "pronounce": "تْرَانْسْفُورْم", "ex_en": "He transformed the garden into a magical place.", "ar_ex": "حوّلَ الحديقةَ إلى مكانٍ ساحرٍ." },
  { "id": 1241, "en": "transition", "ar": "انتقال / تحوّل", "pronounce": "تْرَانْزِشَن", "ex_en": "The country is going through a difficult transition.", "ar_ex": "تمرُّ البلادُ بمرحلةِ انتقالٍ صعبةٍ." },
  { "id": 1242, "en": "transmit", "ar": "ينقل / يبثّ", "pronounce": "تْرَانْزْمِت", "ex_en": "The radio transmits the signal quickly.", "ar_ex": "ينقلُ الراديو الإشارةَ بسرعةٍ." },
  { "id": 1243, "en": "trap", "ar": "فخ / يحاصر", "pronounce": "تْرَاب", "ex_en": "The animal fell into the trap.", "ar_ex": "وقعَ الحيوانُ في الفخِّ." },
  { "id": 1244, "en": "treasure", "ar": "كنز", "pronounce": "تْرِجَر", "ex_en": "They found ancient treasure in the sea.", "ar_ex": "عثروا على كنزٍ قديمٍ في البحرِ." },
  { "id": 1245, "en": "trial", "ar": "محاكمة / تجربة", "pronounce": "تْرَايَل", "ex_en": "The trial began in the morning.", "ar_ex": "بدأتِ المحاكمةُ صباحًا." },
  { "id": 1246, "en": "tribe", "ar": "قبيلة", "pronounce": "تْرَايْب", "ex_en": "The tribe lives near the river.", "ar_ex": "تعيشُ القبيلةُ قربَ النهرِ." },
  { "id": 1247, "en": "trillion", "ar": "تريليون", "pronounce": "تْرِلْيَن", "ex_en": "The losses reached a trillion dollars.", "ar_ex": "وصلَتِ الخسائرُ إلى تريليونِ دولارٍ." },
  { "id": 1248, "en": "troop", "ar": "قوّة / فرقة عسكرية", "pronounce": "تْرُوب", "ex_en": "The troop was sent to the border.", "ar_ex": "أُرسِلَتِ القواتُ إلى الحدودِ." },
  { "id": 1249, "en": "tropical", "ar": "استوائي", "pronounce": "تْرُوبِكَل", "ex_en": "This plant grows in a tropical climate.", "ar_ex": "ينمو هذا النباتُ في مناخٍ استوائيٍّ." },
  { "id": 1250, "en": "truly", "ar": "حقًّا / فعلًا", "pronounce": "تْرُولِي", "ex_en": "I truly thank you for your help.", "ar_ex": "أشكركَ حقًّا على مساعدتِكَ." },
  { "id": 1251, "en": "trust", "ar": "ثقة / يثق", "pronounce": "تْرَسْت", "ex_en": "Trust is the basis of every relationship.", "ar_ex": "الثقةُ أساسُ كلِّ علاقةٍ." },
  { "id": 1252, "en": "tsunami", "ar": "تسونامي", "pronounce": "تْسُونَامِي", "ex_en": "The tsunami hit the coast hard.", "ar_ex": "ضربَ التسونامي الساحلَ بقوّةٍ." },
  { "id": 1253, "en": "tune", "ar": "لحن / نغمة", "pronounce": "تُن", "ex_en": "I liked the tune of this song.", "ar_ex": "أحببتُ لحنَ هذه الأغنيةِ." },
  { "id": 1254, "en": "tunnel", "ar": "نفق", "pronounce": "تَنَل", "ex_en": "We passed through a long tunnel.", "ar_ex": "مررنا عبرَ نفقٍ طويلٍ." },
  { "id": 1255, "en": "ultimate", "ar": "نهائي / أقصى", "pronounce": "أَلْتِمِت", "ex_en": "This is the ultimate goal of the project.", "ar_ex": "هذا هو الهدفُ النهائيُّ للمشروعِ." },
  { "id": 1256, "en": "ultimately", "ar": "في النهاية / في المطاف الأخير", "pronounce": "أَلْتِمِتْلِي", "ex_en": "Ultimately, everyone agreed.", "ar_ex": "في النهايةِ، وافقَ الجميعُ." },
  { "id": 1257, "en": "unacceptable", "ar": "غير مقبول", "pronounce": "أَنْأَكْسِبْتَبُل", "ex_en": "This behavior is unacceptable.", "ar_ex": "هذا التصرّفُ غيرُ مقبولٍ أبدًا." },
  { "id": 1258, "en": "uncertainty", "ar": "عدم يقين", "pronounce": "أَنْسِرْتَنْتِي", "ex_en": "There is uncertainty in the market.", "ar_ex": "تسودُ حالةٌ من عدمِ اليقينِ في السوقِ." },
  { "id": 1259, "en": "unconscious", "ar": "فاقد الوعي", "pronounce": "أَنْكُونْشَس", "ex_en": "He was unconscious after the accident.", "ar_ex": "كان فاقدًا للوعيِ بعدَ الحادثِ." },
  { "id": 1260, "en": "undergo", "ar": "يخضع / يمرّ بـ", "pronounce": "أَنْدَرْغُو", "ex_en": "He had to undergo a difficult surgery.", "ar_ex": "خضعَ لعمليّةٍ جراحيّةٍ صعبةٍ." },
  { "id": 1261, "en": "undertake", "ar": "يتعهّد / يضطلع بـ", "pronounce": "أَنْدَرْتَيْك", "ex_en": "He undertook to do the task himself.", "ar_ex": "تعهّدَ بتنفيذِ المهمّةِ بنفسِهِ." },
  { "id": 1262, "en": "unexpected", "ar": "غير متوقَّع", "pronounce": "أَنْإِكْسْبِكْتِد", "ex_en": "His arrival was unexpected.", "ar_ex": "كان وصولُهُ غيرَ متوقَّعٍ." },
  { "id": 1263, "en": "unfold", "ar": "ينكشف / يتطوّر", "pronounce": "أَنْفُولْد", "ex_en": "The story began to unfold gradually.", "ar_ex": "بدأتْ القصّةُ تنكشفُ تدريجيًّا." },
  { "id": 1264, "en": "unfortunate", "ar": "سيّئ الحظ / غير محظوظ", "pronounce": "أَنْفُورْتْشُنِت", "ex_en": "He was unfortunate in the match.", "ar_ex": "كان حظُّهُ سيّئًا في المباراةِ." },
  { "id": 1265, "en": "unique", "ar": "فريد / مميّز", "pronounce": "يُونِيك", "ex_en": "Every person has a unique style.", "ar_ex": "لكلِّ شخصٍ أسلوبٌ فريدٌ." },
  { "id": 1266, "en": "unite", "ar": "يوحّد / يتّحد", "pronounce": "يُونَايْت", "ex_en": "The teams united to achieve the goal.", "ar_ex": "اتّحدَتِ الفرقُ لتحقيقِ الهدفِ." },
  { "id": 1267, "en": "unity", "ar": "وحدة", "pronounce": "يُونِتِي", "ex_en": "Unity was the source of their strength.", "ar_ex": "كانتْ الوحدةُ سببَ قوّتِهِم." },
  { "id": 1268, "en": "universal", "ar": "عالمي / شامل", "pronounce": "يُونِفِرْسَل", "ex_en": "This is a universal law, not a local one.", "ar_ex": "هذا قانونٌ عالميٌّ لا محلّيٌّ." },
  { "id": 1269, "en": "universe", "ar": "الكون", "pronounce": "يُونِفِرْس", "ex_en": "The universe is wider than we imagine.", "ar_ex": "الكونُ أوسعُ ممّا نتخيّلُ." },
  { "id": 1270, "en": "unknown", "ar": "مجهول", "pronounce": "أَنْنُون", "ex_en": "An unknown person came to the door.", "ar_ex": "جاءَ شخصٌ مجهولُ الهويّةِ إلى البابِ." },
  { "id": 1271, "en": "upper", "ar": "علوي / أعلى", "pronounce": "أَبَر", "ex_en": "The upper floor is quieter.", "ar_ex": "الطابقُ العلويُّ أكثرُ هدوءًا." },
  { "id": 1272, "en": "upwards", "ar": "إلى الأعلى", "pronounce": "أَبْوَرْدْز", "ex_en": "The smoke moved upwards.", "ar_ex": "ارتفعَ الدخانُ إلى الأعلى." },
  { "id": 1273, "en": "urban", "ar": "حضري / مدني", "pronounce": "أُورْبَن", "ex_en": "Most people live in urban areas.", "ar_ex": "يعيشُ معظمُ السكانِ في مناطقَ حضريّةٍ." },
  { "id": 1274, "en": "urge", "ar": "يحثّ / يدفع", "pronounce": "أُورْج", "ex_en": "The teacher urged us to read daily.", "ar_ex": "حثَّنا المعلّمُ على القراءةِ يوميًّا." },
  { "id": 1275, "en": "urgent", "ar": "عاجل", "pronounce": "أُورْجَنْت", "ex_en": "This is an urgent case and needs action.", "ar_ex": "هذه حالةٌ عاجلةٌ وتحتاجُ إلى تدخّلٍ." },
  { "id": 1276, "en": "usage", "ar": "استخدام / استعمال", "pronounce": "يُوسِج", "ex_en": "The usage of this word changes according to the context.", "ar_ex": "يختلفُ استخدامُ هذه الكلمةِ حسبَ السياقِ." },
  { "id": 1277, "en": "useless", "ar": "عديم الفائدة", "pronounce": "يُوسْلِس", "ex_en": "This device was useless.", "ar_ex": "كان هذا الجهازُ عديمَ الفائدةِ." },
  { "id": 1278, "en": "valid", "ar": "صالح / ساري المفعول", "pronounce": "فَالِد", "ex_en": "This certificate is valid for two years.", "ar_ex": "هذه الشهادةُ صالحةٌ لسنتينِ." },
  { "id": 1279, "en": "variation", "ar": "اختلاف / تنوّع", "pronounce": "فِيرِيَيْشَن", "ex_en": "There are many variations between the two versions.", "ar_ex": "توجدُ اختلافاتٌ كثيرةٌ بينَ النسختينِ." },
  { "id": 1280, "en": "vary", "ar": "يتغيّر / يتنوّع", "pronounce": "فِيرِي", "ex_en": "Prices vary every day.", "ar_ex": "تتغيّرُ الأسعارُ كلَّ يومٍ." },
  { "id": 1281, "en": "vast", "ar": "شاسع / واسع جدًا", "pronounce": "فَاَسْت", "ex_en": "The desert extends over a vast area.", "ar_ex": "تمتدُّ الصحراءُ على مساحةٍ شاسعةٍ." },
  { "id": 1282, "en": "venue", "ar": "مكان إقامة فعالية", "pronounce": "فِينْيُو", "ex_en": "The party was held at a beautiful venue.", "ar_ex": "أُقيمَ الحفلُ في مكانٍ جميلٍ." },
  { "id": 1283, "en": "vertical", "ar": "عمودي", "pronounce": "فِرْتِكَل", "ex_en": "The line was completely vertical.", "ar_ex": "كان الخطُّ عموديًّا تمامًا." },
  { "id": 1284, "en": "via", "ar": "عبر / عن طريق", "pronounce": "فَايَا", "ex_en": "He sent the message via email.", "ar_ex": "أرسلَ الرسالةَ عبرَ البريدِ الإلكترونيِّ." },
  { "id": 1285, "en": "victory", "ar": "نصر", "pronounce": "فِكْتُورِي", "ex_en": "The victory was a historic moment.", "ar_ex": "كان النصرُ لحظةً تاريخيّةً." },
  { "id": 1286, "en": "victorious", "ar": "منتصر", "pronounce": "فِكْتُورِيَس", "ex_en": "They returned victorious after the battle.", "ar_ex": "عادوا منتصرينَ بعدَ المعركةِ." },
  { "id": 1287, "en": "viewpoint", "ar": "وجهة نظر", "pronounce": "فْيُوبُوينْت", "ex_en": "Everyone has a different viewpoint.", "ar_ex": "لكلِّ شخصٍ وجهةُ نظرٍ مختلفةٌ." },
  { "id": 1288, "en": "violence", "ar": "عنف", "pronounce": "فَايُلَنْس", "ex_en": "War leads to more violence.", "ar_ex": "تؤدّي الحربُ إلى مزيدٍ من العنفِ." },
  { "id": 1289, "en": "virtual", "ar": "افتراضي", "pronounce": "فِرْتشُوَل", "ex_en": "Virtual learning has become common.", "ar_ex": "أصبحَ التعلّمُ الافتراضيُّ شائعًا." },
  { "id": 1290, "en": "visa", "ar": "تأشيرة", "pronounce": "فِيزَا", "ex_en": "You need a visa to enter the country.", "ar_ex": "تحتاجُ إلى تأشيرةٍ لدخولِ البلدِ." },
  { "id": 1291, "en": "visible", "ar": "مرئي / ظاهر", "pronounce": "فِزِبُل", "ex_en": "The mountain was visible from the window.", "ar_ex": "كان الجبلُ مرئيًّا من النافذةِ." },
  { "id": 1292, "en": "vision", "ar": "رؤية / بصر", "pronounce": "فِجَن", "ex_en": "He had a clear vision for the future.", "ar_ex": "كانت لهُ رؤيةٌ واضحةٌ للمستقبلِ." },
  { "id": 1293, "en": "visual", "ar": "بصري", "pronounce": "فِجُوَل", "ex_en": "I need a visual explanation of the idea.", "ar_ex": "أحتاجُ إلى شرحٍ بصريٍّ للفكرةِ." },
  { "id": 1294, "en": "vital", "ar": "حيوي / ضروري", "pronounce": "فَايْتَل", "ex_en": "Water is vital for every living thing.", "ar_ex": "الماءُ ضروريٌّ لكلِّ كائنٍ حيٍّ." },
  { "id": 1295, "en": "vitamin", "ar": "فيتامين", "pronounce": "فَايْتَمِن", "ex_en": "Oranges contain many vitamins.", "ar_ex": "يحتوي البرتقالُ على فيتاميناتٍ كثيرةٍ." },
  { "id": 1296, "en": "volume", "ar": "مستوى الصوت / حجم", "pronounce": "فَالْيُوم", "ex_en": "He lowered the volume of the music a little.", "ar_ex": "خفّضَ صوتَ الموسيقى قليلًا." },
  { "id": 1297, "en": "voluntarily", "ar": "طوعًا / بشكلٍ اختياري", "pronounce": "فُولَنْتِرِلِي", "ex_en": "He took part in the work voluntarily.", "ar_ex": "شاركَ في العملِ طوعًا." },
  { "id": 1298, "en": "voluntary", "ar": "تطوّعي / اختياري", "pronounce": "فُولَنْتَرِي", "ex_en": "The work was entirely voluntary.", "ar_ex": "كان العملُ تطوّعيًّا بالكاملِ." },
  { "id": 1299, "en": "voting", "ar": "تصويت", "pronounce": "فُوتِنْغ", "ex_en": "Voting began in the morning.", "ar_ex": "بدأتْ عمليّةُ التصويتِ في الصباحِ." },
  { "id": 1300, "en": "wage", "ar": "أجر / راتب", "pronounce": "وِيج", "ex_en": "The workers demanded higher wages.", "ar_ex": "طالبَ العمالُ برفعِ الأجورِ." },
  { "id": 1301, "en": "wander", "ar": "يتجوّل / يهيم", "pronounce": "وَانْدَر", "ex_en": "He wandered in the forest without a map.", "ar_ex": "تجوّلَ في الغابةِ دونَ خريطةٍ." },
  { "id": 1302, "en": "warming", "ar": "احترار / تدفئة", "pronounce": "وُورْمِنْغ", "ex_en": "The greenhouse effect caused more warming.", "ar_ex": "تسبّبَ الاحتباسُ في ازديادِ الاحترارِ." },
  { "id": 1303, "en": "weakness", "ar": "ضعف / نقطة ضعف", "pronounce": "وِيكْنِس", "ex_en": "This point was the weakness of the plan.", "ar_ex": "كانتْ هذه النقطةُ أضعفَ جزءٍ في الخطةِ." },
  { "id": 1304, "en": "wealth", "ar": "ثروة", "pronounce": "وِلْث", "ex_en": "Wealth brings great responsibility.", "ar_ex": "تجلبُ الثروةُ معها مسؤوليةً كبيرةً." },
  { "id": 1305, "en": "wealthy", "ar": "ثري", "pronounce": "وِلْثِي", "ex_en": "He lives in a wealthy neighborhood.", "ar_ex": "يعيشُ في حيٍّ ثريٍّ." },
  { "id": 1306, "en": "weekly", "ar": "أسبوعي / أسبوعيًّا", "pronounce": "وِيكْلِي", "ex_en": "The magazine is published weekly.", "ar_ex": "تُنشَرُ المجلّةُ أسبوعيًّا." },
  { "id": 1307, "en": "weird", "ar": "غريب / عجيب", "pronounce": "وِيرْد", "ex_en": "His appearance was a bit weird.", "ar_ex": "كان منظرُهُ غريبًا بعضَ الشيءِ." },
  { "id": 1308, "en": "welfare", "ar": "رفاه / رعاية اجتماعية", "pronounce": "وِلْفِير", "ex_en": "The state cares about the welfare of citizens.", "ar_ex": "تهتمُّ الدولةُ برفاهِ المواطنينَ." },
  { "id": 1309, "en": "wheat", "ar": "قمح", "pronounce": "وِيت", "ex_en": "Wheat is grown in these fields.", "ar_ex": "يُزرَعُ القمحُ في هذه الحقولِ." },
  { "id": 1310, "en": "whereas", "ar": "بينما / في حين أن", "pronounce": "وِيرْأَز", "ex_en": "I like summer, whereas my brother prefers winter.", "ar_ex": "أنا أحبُّ الصيفَ، بينما أخي يفضّلُ الشتاءَ." },
  { "id": 1311, "en": "wherever", "ar": "حيثما", "pronounce": "وِيرْإِفَر", "ex_en": "I will go wherever you go.", "ar_ex": "سأذهبُ إلى حيثُما تذهبُ." },
  { "id": 1312, "en": "whisper", "ar": "يهمس", "pronounce": "وِسْبَر", "ex_en": "He whispered a small secret in my ear.", "ar_ex": "همسَ في أذني بسرٍّ صغيرٍ." },
  { "id": 1313, "en": "whoever", "ar": "أيّ شخص / مَن", "pronounce": "هوإِفَر", "ex_en": "Whoever works hard will succeed.", "ar_ex": "سيفوزُ مَن يعملُ بجدٍّ." },
  { "id": 1314, "en": "whom", "ar": "مَن / من الذي", "pronounce": "هُوم", "ex_en": "Whom were you talking to?", "ar_ex": "مع من كنتَ تتحدّثُ؟" },
  { "id": 1315, "en": "widely", "ar": "على نطاقٍ واسع", "pronounce": "وَايْدْلِي", "ex_en": "This medicine is widely used.", "ar_ex": "يُستَخدَمُ هذا الدواءُ على نطاقٍ واسعٍ." },
  { "id": 1316, "en": "widespread", "ar": "واسع الانتشار", "pronounce": "وَايْدْسْبْرِد", "ex_en": "The idea became widespread.", "ar_ex": "انتشرتِ الفكرةُ انتشارًا واسعًا." },
  { "id": 1317, "en": "widow", "ar": "أرملة", "pronounce": "وِدُو", "ex_en": "The widow lived alone for years.", "ar_ex": "عاشتِ الأرملةُ وحدها سنواتٍ." },
  { "id": 1318, "en": "wildlife", "ar": "حياة برية", "pronounce": "وَايْلْدْلَايْف", "ex_en": "Wildlife must be protected.", "ar_ex": "يجبُ حمايةُ الحياةِ البريّةِ." },
  { "id": 1319, "en": "willing", "ar": "راغب / مستعد", "pronounce": "وِلِنْغ", "ex_en": "I am willing to help you.", "ar_ex": "أنا مستعد`ٌ لمساعدتِكَ." },
  { "id": 1320, "en": "wire", "ar": "سلك", "pronounce": "وَايَر", "ex_en": "The wire was exposed and dangerous.", "ar_ex": "كان السلكُ مكشوفًا وخطيرًا." },
  { "id": 1321, "en": "wisdom", "ar": "حكمة", "pronounce": "وِزْدَم", "ex_en": "Wisdom comes with experience.", "ar_ex": "الحكمةُ تأتي مع التجربةِ." },
  { "id": 1322, "en": "wise", "ar": "حكيم", "pronounce": "وَايْز", "ex_en": "His decision was wise and thoughtful.", "ar_ex": "كان قرارُهُ حكيمًا ومدروسًا." },
  { "id": 1323, "en": "withdraw", "ar": "ينسحب / يسحب", "pronounce": "وِذْدْرُو", "ex_en": "He withdrew money from the bank.", "ar_ex": "سحبَ المالَ من البنكِ." },
  { "id": 1324, "en": "witness", "ar": "شاهد / يشهد", "pronounce": "وِتْنِس", "ex_en": "He was a witness to the accident.", "ar_ex": "كان شاهدًا على الحادثِ." },
  { "id": 1325, "en": "wolf", "ar": "ذئب", "pronounce": "وُولْف", "ex_en": "The wolf howling at night.", "ar_ex": "سمعوا عواءَ الذئبِ ليلًا." },
  { "id": 1326, "en": "workforce", "ar": "قوّة عاملة", "pronounce": "وُورْكْفُورس", "ex_en": "The company needs a skilled workforce.", "ar_ex": "تحتاجُ الشركةُ إلى قوّةِ عملٍ ماهرةٍ." },
  { "id": 1327, "en": "workplace", "ar": "مكان العمل", "pronounce": "وُورْكْبْلَيْس", "ex_en": "The workplace must be improved.", "ar_ex": "يجبُ تحسينُ بيئةِ العملِ." },
  { "id": 1328, "en": "workshop", "ar": "ورشة عمل", "pronounce": "وُورْكْشُوب", "ex_en": "I attended a workshop about design.", "ar_ex": "حضرتُ ورشةَ عملٍ عن التصميمِ." },
  { "id": 1329, "en": "worm", "ar": "دودة", "pronounce": "وُورْم", "ex_en": "He found a small worm in the soil.", "ar_ex": "وجدَ دودةً صغيرةً في التربةِ." },
  { "id": 1330, "en": "wound", "ar": "جرح / يجرح", "pronounce": "وُونْد", "ex_en": "The wound was deep in his leg.", "ar_ex": "كان الجرحُ عميقًا في ساقِهِ." },
  { "id": 1331, "en": "wrap", "ar": "يلفّ", "pronounce": "رَاب", "ex_en": "He wrapped the gift in colored paper.", "ar_ex": "لفَّ الهديّةَ بورقٍ ملوّنٍ." },
  { "id": 1332, "en": "wrist", "ar": "معصم", "pronounce": "رِسْت", "ex_en": "I felt pain in my wrist.", "ar_ex": "أصابَني ألمٌ في معصمي." },
  { "id": 1333, "en": "zone", "ar": "منطقة / نطاق", "pronounce": "زُون", "ex_en": "The city is divided into several zones.", "ar_ex": "تُقسَّمُ المدينةُ إلى عدّةِ مناطقَ." }

	
